from urllib.parse import urlparse
from flask import Flask, request, redirect, url_for, session, render_template_string

app = Flask(__name__)
app.secret_key = 'your-secret-key-change-in-production'

# Allowlist of safe domains for redirects
ALLOWED_HOSTS = ['localhost', '127.0.0.1', 'yourdomain.com', 'www.yourdomain.com']

# Allowlist of safe internal paths
SAFE_PATHS = ['/dashboard', '/profile', '/settings', '/home']

def is_safe_url(target):
    """
    Validate that the redirect URL is safe.
    Only allows redirects to:
    1. Relative URLs (same domain)
    2. URLs with allowed hosts
    3. URLs matching safe internal paths
    """
    if not target:
        return False
    
    # Parse the target URL
    parsed = urlparse(target)
    
    # If there's a netloc (domain), check if it's in the allowlist
    if parsed.netloc:
        if parsed.netloc not in ALLOWED_HOSTS:
            return False
    
    # Check if the path starts with allowed paths
    if parsed.path:
        # Ensure path starts with / and doesn't contain dangerous patterns
        if not parsed.path.startswith('/'):
            return False
        
        # Prevent protocol-relative URLs (//evil.com)
        if parsed.path.startswith('//'):
            return False
        
        # Optional: Check against safe paths allowlist
        # Uncomment if you want strict path validation
        # if not any(parsed.path.startswith(safe_path) for safe_path in SAFE_PATHS):
        #     return False
    
    # Reject URLs with schemes other than http/https or no scheme (relative URLs)
    if parsed.scheme and parsed.scheme not in ['http', 'https']:
        return False
    
    return True

def get_redirect_target():
    """
    Get the redirect target from request parameters or referrer.
    Returns None if no safe target is found.
    """
    # Check 'next' parameter first
    for target in [request.args.get('next'), request.form.get('next')]:
        if target and is_safe_url(target):
            return target
    
    # Check referrer as fallback
    referrer = request.referrer
    if referrer and is_safe_url(referrer):
        return referrer
    
    return None

def redirect_to_intended_destination(default='dashboard'):
    """
    Redirect user to their intended destination after authentication.
    Falls back to a default safe route if no valid destination is found.
    
    Args:
        default: The default route name to redirect to (without leading slash)
    
    Returns:
        Flask redirect response
    """
    target = get_redirect_target()
    
    if target:
        return redirect(target)
    
    # Fallback to default safe route
    return redirect(url_for(default))

